LOCK TABLES `claims` WRITE;
/*!40000 ALTER TABLE `claims` DISABLE KEYS */;
INSERT INTO `claims` VALUES (1,'AI coding tools produce a net developer productivity gain of approximately 15–20% in enterprise settings, after accounting for the rework overhead introduced by AI-generated code.','observation',NULL,NULL,'Primary headline finding from Stanford study. Net figure after subtracting rework.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(2,'A significant portion of AI-driven productivity gains are illusory — the gross increase of 30–40% in code output is roughly halved by rework costs from fixing bugs and cleaning up AI-generated problems.','observation',NULL,NULL,'The gross-to-net gap is the studys most actionable finding for engineering leaders.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(3,'AI impact on developer productivity is modulated by five factors: task complexity, codebase maturity (greenfield vs. brownfield), programming language popularity, codebase size, and context window length.','framework',NULL,NULL,'Five-factor framework from Stanford study. Each factor independently modulates the baseline 15–20% net gain.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(4,'AI productivity gains vary dramatically by task context — from 30–40% for low-complexity greenfield work down to 0–10% for high-complexity brownfield tasks.','observation',NULL,NULL,'Based on complexity-by-maturity matrix from 136 teams across 27 companies.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(5,'AI coding tools can actively decrease developer productivity when applied to complex tasks in less popular programming languages such as COBOL, Haskell, and Elixir.','observation',NULL,NULL,'Developers in this situation tend to abandon AI tooling entirely.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(6,'AI productivity gains diminish sharply as codebase size increases, driven by context window limitations, signal-to-noise degradation, and dependency complexity.','observation',NULL,NULL,'Presenter characterizes this as more theoretical than empirically proven. Illustrative trend rather than rigorous measurement.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(7,'Most existing studies on AI developer productivity are methodologically flawed — they rely on volume-based metrics that ignore task size, greenfield-only experiments that do not reflect real working conditions, or self-reported surveys that correlate poorly with actual output.','assertion',NULL,NULL,'Central methodological critique motivating the Stanford study approach.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(8,'Developer self-assessment of productivity is unreliable — developers misjudge their own productivity by approximately 30 percentile points, making surveys nearly useless for measuring actual output.','assertion',NULL,NULL,'Based on small validation study (n=43). Directionally strong but sample is limited.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 3, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(9,'LLM coding performance degrades significantly as context length increases — dropping from approximately 90% accuracy at 1,000 tokens to 50% at 32,000 tokens — even for models with very large context windows.','observation',NULL,NULL,'Cites No LIMA paper. External research, may not directly map to current enterprise AI tools given rapid model improvements.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(10,'Developer productivity should be measured by the functionality of code delivered over time, not by proxy metrics like lines of code, commit counts, or PR throughput.','principle',NULL,NULL,'Foundational methodological principle underlying the Stanford study. The rework/refactoring distinction depends on this approach.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(11,'LLM adoption surveys produce misleading results because they fail to distinguish between autocomplete workflows and agentic workflows where the LLM directly reads and edits code files.','assertion',NULL,NULL,'Related to claim #7 â€” both critique survey methodology but from different angles. #7 focuses on metric flaws, this focuses on workflow conflation. Candidate for clustering.','2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 2, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(12,'Developers who get the most value from LLMs prefer agentic approaches that allow the LLM to directly read and edit source code, rather than autocomplete-style tools like Copilot.','observation',NULL,NULL,'Based on Fowler personal network observation, not controlled study.','2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(13,'The future impact of LLMs on software development careers is fundamentally unknowable, and anyone claiming certainty about it is unreliable.','assertion',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 2, \"factuality\": 2}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(14,'AI is an economic bubble following the historical pattern of every major technological advance, and its collapse is certain even though its timing is not.','assertion',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 1, \"soundness\": 2, \"factuality\": 2}, \"substance\": {\"impact\": 2, \"originality\": 3, \"practicality\": 1}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(15,'LLM hallucinations are not a defect but the fundamental mechanism — all LLM output is hallucination, and useful outputs are simply hallucinations that happen to be correct.','assertion',NULL,NULL,'Attributed to Rebecca Parsons. Reframes the entire conversation about LLM reliability.','2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(16,'Practitioners should ask LLMs the same question multiple times with wording variations and compare answers, because the differences between answers can be as informative as the answers themselves.','recommendation',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(17,'LLMs may mark the point where software engineering joins other engineering disciplines in confronting non-determinism, requiring tolerance and variability management that was previously unnecessary.','prediction',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 2}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(18,'LLMs dramatically expand the attack surface of software systems, and the combination of private data access, untrusted content exposure, and external communication capability makes certain agent architectures fundamentally unsafe.','assertion',NULL,NULL,'Based on Simon Willison Lethal Trifecta framework.','2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(19,'LLMs will confidently report that tests pass when they actually fail, creating a trustworthiness gap that would be unacceptable in a human colleague.','observation',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 4, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(20,'LLMs should never be used to calculate answers that can be computed deterministically, though they can generate code that performs the calculation.','principle',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 3, \"originality\": 1, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(21,'Prompt injection is an unsolved, systemic property of current LLM architectures, not a patchable bug — LLMs fundamentally cannot distinguish between data they are processing and instructions they should follow.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(22,'The \"Lethal Trifecta\" — the simultaneous presence of sensitive data access, untrusted content exposure, and external communication capability — defines the condition under which agentic LLMs are most vulnerable to catastrophic attack.','framework',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 5, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(23,'As of early 2025, no agentic AI system is secure against prompt injection attacks, and most vendors are failing to treat this as the existential security problem it is.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(24,'Agentic browser extensions that connect to authenticated browser sessions cannot be built safely and the entire architecture is fatally flawed.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(25,'Effective mitigation of agentic LLM security risk requires eliminating or isolating at least one leg of the Lethal Trifecta — sensitive data access, untrusted content exposure, or external communication capability.','principle',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(26,'Task decomposition — separating privileged sessions that access sensitive codebases from isolated sessions that interact with untrusted external content — applies the Principle of Least Privilege at the agent session level and is one of the most practical agentic security patterns.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(27,'Container sandboxing reduces but does not eliminate agentic LLM risk, because the Lethal Trifecta can still be triggered inside a container if the containerized session has credentials and untrusted content simultaneously.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(28,'The proliferation of MCP servers and agent frameworks built by startups and hobbyists with limited security discipline makes standard software vetting practices more important — not less — in the agentic era.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(29,'Developers using LLM agents remain fully responsible for all outputs and side effects regardless of which tool produced them — the \"head chef\" framing means you cannot blame your sous chef.','principle',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 1, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(30,'Any internet access by an LLM agent is a potential data exfiltration channel, including seemingly benign operations like image loads via GET requests with query parameters.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(31,'Production credentials should never be stored in files accessible to LLM agents — environment variables or in-memory credential managers (such as 1Password CLI) are safer because they limit exposure time and scope.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 1, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(32,'MCP servers with write or publish capabilities — including public issue trackers and shared documents — should be treated as potential exfiltration vectors when sensitive data is present in the same session.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(33,'The MCP Registry launch is a step toward a vetted ecosystem but currently functions as a directory, not a security certification — the presence of a server in the registry does not imply it has been security-audited.','observation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(34,'AI agents deliver reliable production value only when operating inside structured conventions, deterministic processes, and well-defined specifications — ad hoc prompting is insufficient for production-grade agentic systems.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(35,'Spec-driven development (SDD) — storing structured specifications and persistent project context alongside application code in the repository — is the reliable approach to governing what agentic systems produce.','framework',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(36,'The most consistent failure point in software development, with or without AI, is the handoff between requirements, design, and implementation — decisions disappear and reasoning gets re-litigated because it was never recorded.','observation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(37,'Agents should not orchestrate themselves — giving agents meta-level control over phase transitions and task sequencing causes performance degradation on larger codebases, including skipped steps, circular dependencies, and analysis loops.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(38,'Rule-based workflow engines that enforce phase transitions and dependency management are more reliable than self-orchestrating agent systems.','principle',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(39,'A network of focused, single-responsibility agents is more reliable than a single general-purpose agent handling the full development lifecycle — specialization outperforms generalization in agentic software systems.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(40,'The specialized agent model is analogous to a microservices architecture: it trades one complex system for multiple simpler systems plus the orchestration cost of managing interfaces between them.','framework',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(41,'Automated inline evaluation at every pipeline stage is what makes an agentic development pipeline trustworthy — without it, errors propagate downstream where they become far more expensive to correct.','principle',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(42,'A two-layer evaluation approach — deterministic checks first (linters, tests, structural validation), followed by a critic agent for judgment-requiring checks — provides robust quality gates at each pipeline phase.','framework',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(43,'A knowledge agent that actively accumulates logged assumptions and decisions during feature development — surfaced through version control and reviewable in pull requests — builds institutional memory that persists beyond any individual agent session.','framework',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 5, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(44,'When an AI agent encounters uncertainty during development, logging the assumption as a structured, discrete item rather than burying it in freeform notes makes it reviewable alongside code and correctable with durable documentation.','recommendation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(45,'The claim that AI agents become better primarily through increased autonomy and raw capability is undermined by production evidence — constraints and structure, not raw capability, are what enable reliable agentic output.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(46,'Folder and naming conventions in agentic systems serve a dual purpose: organizing artifacts for human developers and making the system machine-readable for the workflow engine, collapsing human and machine legibility into a single convention.','observation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(47,'The performance advantages of deterministic orchestration over self-orchestrating agents and of specialized agents over generalist agents are based on practitioner observation across client engagements, not controlled empirical research — the patterns may be sound but lack quantitative validation.','observation',NULL,NULL,'Methodological caveat from the source itself; related to claim #7 (study methodology critique)','2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}');
