INSERT INTO `contributors` VALUES (1,'Yegor Denisov-Blanch','Denisov-Blanch, Yegor','Stanford University','Researcher','Yegor Denisov-Blanch is a researcher with the Stanford Software Engineering Productivity Research Group, where he studies how AI is changing software development. His research analyzes data from hundreds of organizations and over 50,000 engineers to quantify the real-world impact of AI on engineering teams. His work has been featured at the United Nations and in the Washington Post, and has been used to inform World Bank guidance on AI labor impacts.','https://aiconference.com/wp-content/uploads/2025/08/Yegor-Denisov-Blanch-1.jpg','https://www.yegordb.com',NULL,'2026-03-01 19:24:30','{\"tier\": 2, \"notes\": \"Stanford Research Scientist with access to unique dataset of 120k+ engineers across 600+ companies. Ghost Engineers study went viral (Washington Post, Elon Musk amplification, UN, World Bank). However, thin publication record (4 papers, 5 citations), no PhD, and Ghost Engineers methodology drew significant criticism for lack of peer review.\", \"reach\": 4, \"authority\": 3, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(2,'Martin Fowler','Fowler, Martin','Thoughtworks','Author and Software Development Thought Leader','Chief Scientist at Thoughtworks. Author of Refactoring and Patterns of Enterprise Application Architecture. Pioneer of agile software development and co-author of the Agile Manifesto. Specializes in object-oriented analysis, UML, patterns, and agile methodologies.','https://martinfowler.com/mf.jpg','https://martinfowler.com',NULL,'2026-03-01 21:49:55','{\"tier\": 1, \"notes\": \"Chief Scientist at Thoughtworks. Co-author of the Agile Manifesto. Author of Refactoring and Patterns of Enterprise Application Architecture. martinfowler.com is one of the most influential software engineering sites globally. Decades of industry-defining work with no controversy.\", \"reach\": 5, \"authority\": 5, \"expertise\": 5, \"reputation\": 5, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(3,'Korny Sietsma','Sietsma, Korny','Liberis','Author','Korny Sietsma (Kornelis Sietsma) is a software engineer and engineering lead with over 19 years of experience, currently working as a Principal Engineer at John Lewis Partnership after several years at Liberis. He spent 12 years at Thoughtworks before moving into product engineering roles. His expertise spans agile practices, software architecture, code visualisation, and agentic AI security.','https://avatars.githubusercontent.com/u/17765?v=4','https://blog.korny.info',NULL,'2026-03-01 23:52:11','{\"tier\": 3, \"notes\": \"Experienced practitioner with 25+ years and 12 years at ThoughtWorks. Published on martinfowler.com with personal endorsement from Fowler. Created Polyglot Code Tools. Modest personal reach but respected for careful, well-sourced technical writing.\", \"reach\": 2, \"authority\": 2, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(4,'Daniel Sheard','Sheard, Daniel','QuantumBlack, AI by McKinsey','Distinguished Engineer','Daniel Sheard is a Distinguished Engineer at QuantumBlack, AI by McKinsey, based in London. He focuses on agentic AI systems and software engineering patterns, and is pursuing part-time doctoral research at the University of Oxford. He co-authors technical thought leadership for QuantumBlack on building production-grade agentic workflows.',NULL,'https://www.linkedin.com/in/danielsheard',NULL,'2026-03-02 00:26:41','{\"tier\": 2, \"notes\": \"Distinguished Engineer at QuantumBlack (McKinsey) with deep production experience in agentic AI systems. Pursuing part-time PhD at Oxford. Institutional authority through McKinsey brand, but limited independent public profile. Writes substantive technical content on agentic workflows deployed at client engagements.\", \"reach\": 2, \"authority\": 3, \"expertise\": 4, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(5,'Jo Stichbury','Stichbury, Jo','QuantumBlack, AI by McKinsey','Technical Editor','Jo Stichbury is a Technical Editor and writer at QuantumBlack, AI by McKinsey, specializing in data science, machine learning, and AI. She is based in London and educated at the University of Cambridge. She has contributed to open-source projects including Kedro and Vizro, and writes and edits technical thought leadership for QuantumBlack.','https://github.com/stichbury.png','https://github.com/stichbury',NULL,'2026-03-02 00:26:41','{\"tier\": 2, \"notes\": \"Cambridge PhD with 25+ years in software. Author of 3 published books (Wiley). Core team member on Kedro (9,000+ GitHub stars, Linux Foundation). DZone CORE expert. Prolific across Towards Data Science, DZone, and other platforms. Award-winning documentation. Primarily an editor/writer who shapes QuantumBlack technical voice.\", \"reach\": 3, \"authority\": 3, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}');
