DROP TABLE IF EXISTS `evidence`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `evidence` (
  `id` int NOT NULL AUTO_INCREMENT,
  `content` text NOT NULL COMMENT 'The evidence itself, in your voice unless quoting',
  `source_id` int NOT NULL COMMENT 'Always traces to original source',
  `evidence_type` enum('empirical','case_study','expert_opinion','anecdotal','theoretical','statistical','other') NOT NULL DEFAULT 'expert_opinion',
  `verbatim_quote` text COMMENT 'Exact quote when attribution matters, NULL otherwise',
  `evaluation_results` json DEFAULT NULL COMMENT 'Credibility, independence, quality assessments',
  `derived_from_evidence_id` int DEFAULT NULL COMMENT 'If this evidence is citing/echoing another source. Discounted in scoring.',
  `notes` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_evidence_source` (`source_id`),
  KEY `idx_evidence_type` (`evidence_type`),
  KEY `idx_evidence_derived` (`derived_from_evidence_id`),
  CONSTRAINT `evidence_ibfk_1` FOREIGN KEY (`source_id`) REFERENCES `sources` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `evidence_ibfk_3` FOREIGN KEY (`derived_from_evidence_id`) REFERENCES `evidence` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

