-- Table structure for table `sources`
--

DROP TABLE IF EXISTS `sources`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sources` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(500) NOT NULL,
  `source_type` enum('youtube_video','podcast','blog_post','website','academic_paper','book','book_chapter','conference_talk','newsletter','social_media','report','research','documentation','other') NOT NULL,
  `url` varchar(1024) DEFAULT NULL,
  `publication_id` int DEFAULT NULL,
  `publication_date` date DEFAULT NULL,
  `date_collected` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `evaluation_results` json DEFAULT NULL COMMENT 'Flexible evaluation data: credibility, bias, relevance, etc.',
  `content_md` longtext NOT NULL COMMENT 'Full markdown of source material',
  `distillation` longtext,
  `word_count` int GENERATED ALWAYS AS (((length(`content_md`) - length(replace(`content_md`,_utf8mb4' ',_latin1''))) + 1)) STORED,
  `status` enum('collected','distilling','distilled','decomposing','decomposed') NOT NULL DEFAULT 'collected',
  `notes` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_sources_status` (`status`),
  KEY `idx_sources_type` (`source_type`),
