INSERT INTO `themes` VALUES (1,'AI productivity gains are real but overstated','AI coding tools deliver genuine productivity improvements, but the widely cited gross figures are roughly double the actual net gains once rework overhead is accounted for.','The core argument that headline AI productivity numbers are misleading because they ignore the cost of fixing AI-generated problems.','2026-03-01 20:28:43'),(2,'AI effectiveness depends heavily on context','The productivity impact of AI coding tools varies from strongly positive to actively harmful depending on task complexity, codebase maturity, language popularity, codebase size, and context length.','The argument against one-size-fits-all AI adoption — effectiveness is modulated by at least five measurable factors.','2026-03-01 20:28:43');
